const raw = $json.choices?.[0]?.message?.content || "";

const topics = raw
  .split("\n")
  .map(line => line.trim())
  .filter(line => line)
  .map(line => line.replace(/^\d+[\.\)]\s*/, "").trim())
  .filter(line => line.length > 0)
  .slice(0, 5);

return [{ json: { raw, topics } }];

const raw = $json.choices?.[0]?.message?.content || "";

const hooks = raw
  .split("\n")
  .map(line => line.trim())
  .filter(line => line)
  .map(line => line.replace(/^\d+[\.\)]\s*/, "").trim())
  .filter(line => line.length > 0)
  .slice(0, 3);

return {
  topic: $('rename topic').item.json.topic,
  raw_hooks: raw,
  hooks
};

const script = $json.choices?.[0]?.message?.content || "";

return {
  topic: $('rename_hook').item.json.topic,
  hook: $('rename_hook').item.json.hook,
  script: script.trim()
};

function slugify(text) {
  return text
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .trim()
    .replace(/\s+/g, '-')
    .replace(/-+/g, '-')
    .slice(0, 60);
}

const today = new Date().toISOString().slice(0, 10);

return {
  date: today,
  topic: $json.topic,
  hook: $json.hook,
  script: $json.script,
  slug: slugify($json.topic),
  hook_slug: slugify($json.hook)
};

const fs = require('fs');
const path = require('path');

const filename = `${$json.date}_${$json.slug}_${$json.hook_slug}.json`;
const filepath = `/files/scripts/${filename}`;
const dir = path.dirname(filepath);

if (!fs.existsSync(dir)) {
  fs.mkdirSync(dir, { recursive: true });
}

const content = JSON.stringify({
  date: $json.date,
  topic: $json.topic,
  hook: $json.hook,
  script: $json.script,
  slug: $json.slug,
  hook_slug: $json.hook_slug
}, null, 2);

fs.writeFileSync(filepath, content, 'utf8');

return {
  date: $json.date,
  topic: $json.topic,
  hook: $json.hook,
  script: $json.script,
  slug: $json.slug,
  hook_slug: $json.hook_slug,
  script_file: filepath
};

const voiceMap = {
  female: { voice: 'en-US-JennyNeural', image_dir: 'female_host' },
  male: { voice: 'en-US-GuyNeural', image_dir: 'male_host' },
  psych: { voice: 'en-US-AriaNeural', image_dir: 'psych_host' }
};

return $input.all().flatMap(item =>
  Object.entries(voiceMap).map(([variant, config]) => ({
    date: item.json.date,
    topic: item.json.topic,
    hook: item.json.hook,
    script: item.json.script,
    slug: item.json.slug,
    hook_slug: item.json.hook_slug,
    script_file: item.json.script_file,
    variant,
    voice: config.voice,
    voice_id: config.voice,
    image_dir: config.image_dir
  }))
);

const fs = require('fs');
const path = require('path');

const baseName = `${$json.date}_${$json.slug}_${$json.hook_slug}_${$json.variant}`;
const queueDir = '/files/queue/pending';
const queueFile = `${queueDir}/${baseName}.json`;

if (!fs.existsSync(queueDir)) {
  fs.mkdirSync(queueDir, { recursive: true });
}

const payload = {
  job_id: baseName,
  created_at: new Date().toISOString(),
  updated_at: new Date().toISOString(),
  status: 'pending',
  retry_count: 0,
  last_error: null,
  date: $json.date,
  topic: $json.topic,
  hook: $json.hook,
  slug: $json.slug,
  hook_slug: $json.hook_slug,
  variant: $json.variant,
  voice: $json.voice,
  script_file: $json.script_file
};

fs.writeFileSync(queueFile, JSON.stringify(payload, null, 2), 'utf8');

return {
  ...$json,
  base_name: baseName,
  queue_file: queueFile
};

const fs = require('fs');

const logDir = '/files/logs/generation';
if (!fs.existsSync(logDir)) {
  fs.mkdirSync(logDir, { recursive: true });
}

const logEntry = {
  timestamp: new Date().toISOString(),
  status: 'ready_to_upload',
  date: $json.date,
  topic: $json.topic,
  hook: $json.hook,
  variant: $json.variant,
  voice: $json.voice,
  script_file: $json.script_file,
  audio_file: $json.audio_file,
  srt_file: $json.srt_file,
  video_file: $json.video_file,
  queue_file: $json.queue_file,
  upload_task_count: $json.upload_task_count
};

const logFile = `${logDir}/${$json.date}_generation.log`;
fs.appendFileSync(logFile, JSON.stringify(logEntry) + '\n', 'utf8');

return {
  success: true,
  status: 'ready_to_upload',
  date: $json.date,
  topic: $json.topic,
  hook: $json.hook,
  variant: $json.variant,
  audio_file: $json.audio_file,
  srt_file: $json.srt_file,
  video_file: $json.video_file,
  queue_file: $json.queue_file,
  upload_task_count: $json.upload_task_count
};
